// Typed display helpers for [NightshadeEvent].
//
// `event.dart` is auto-generated by flutter_rust_bridge and we cannot
// extend it in place. Instead, this file provides exhaustive
// `switch (event.payload)` mappings on the freezed union variants and
// returns short title + detail strings the UI can render directly.
//
// Why we need this:
//   * The Run Dashboard's "Recent events" feed previously used
//     `RegExp(r'[,)]')` on the freezed `toString()` output to scrape a
//     `message:` field. Any payload field containing a comma broke the
//     scrape and the user saw garbage in the feed.
//   * The new helpers read actual fields off each variant, so adding a
//     new event variant is an exhaustive-switch compiler error rather
//     than a silent runtime regression.
//
// Both helpers are intentionally pure and side-effect free; they take a
// const `NightshadeEvent` and return strings.

import 'event.dart';

/// Returns a short headline-style title for the event suitable for the
/// trigger feed row. Examples:
///   * `EquipmentEvent_Connected(deviceType: ZWO, ...)` → `"Connected"`
///   * `ImagingEvent_ExposureFailed(error: ...)` → `"Exposure failed"`
///
/// The title is constant-length and stable across runs — it never depends
/// on field values, only on the variant.
String nightshadeEventDisplayTitle(NightshadeEvent event) {
  final payload = event.payload;
  switch (payload) {
    case EventPayload_Equipment(field0: final v):
      return _equipmentTitle(v);
    case EventPayload_Imaging(field0: final v):
      return _imagingTitle(v);
    case EventPayload_Guiding(field0: final v):
      return _guidingTitle(v);
    case EventPayload_Sequencer(field0: final v):
      return _sequencerTitle(v);
    case EventPayload_Safety(field0: final v):
      return _safetyTitle(v);
    case EventPayload_System(field0: final v):
      return _systemTitle(v);
    case EventPayload_PolarAlignment():
      return 'Polar alignment update';
    case EventPayload_PolarAlignmentStatus(field0: final v):
      return 'Polar alignment: ${v.status}';
    case EventPayload_PolarAlignmentImage(field0: final v):
      return 'Polar alignment ${v.phase}';
  }
}

/// Returns a longer, field-derived detail line. May be empty when there
/// is no useful per-event detail. Empty results are rendered as a
/// title-only row.
String nightshadeEventDisplayDetail(NightshadeEvent event) {
  final payload = event.payload;
  switch (payload) {
    case EventPayload_Equipment(field0: final v):
      return _equipmentDetail(v);
    case EventPayload_Imaging(field0: final v):
      return _imagingDetail(v);
    case EventPayload_Guiding(field0: final v):
      return _guidingDetail(v);
    case EventPayload_Sequencer(field0: final v):
      return _sequencerDetail(v);
    case EventPayload_Safety(field0: final v):
      return _safetyDetail(v);
    case EventPayload_System(field0: final v):
      return _systemDetail(v);
    case EventPayload_PolarAlignment(field0: final v):
      return 'Total error ${v.totalError.toStringAsFixed(2)}\'';
    case EventPayload_PolarAlignmentStatus(field0: final v):
      return 'Phase ${v.phase} (point ${v.point})';
    case EventPayload_PolarAlignmentImage(field0: final v):
      return v.phase == 'measuring'
          ? 'Measurement ${v.point}/3'
          : 'Adjustment phase';
  }
}

/// True when the event is operationally critical and the dashboard
/// should escalate it to a persistent banner / push notification rather
/// than letting it scroll off the recent-events feed.
///
/// The classification is driven first by the bridge's [EventSeverity]
/// (Rust sets `critical` on park failures, mount errors, FITS save
/// failures, disk exhaustion, etc.) and then by a small set of variant
/// patterns the bridge currently emits at `error` severity but which the
/// user must not miss (e.g. an exposure failure mid-sequence).
bool isCriticalEvent(NightshadeEvent event) {
  if (event.severity == EventSeverity.critical) return true;

  // A small allow-list of error-severity events that the operator needs
  // a persistent banner for — these are the events that, if missed,
  // result in a wasted night.
  final payload = event.payload;
  return switch (payload) {
    EventPayload_Imaging(field0: final v) => switch (v) {
        ImagingEvent_ExposureFailed() => true,
        ImagingEvent_ExposureFailedOld() => true,
        _ => false,
      },
    EventPayload_Safety(field0: final v) => switch (v) {
        SafetyEvent_EmergencyStop() => true,
        SafetyEvent_WeatherUnsafe() => true,
        _ => false,
      },
    EventPayload_System(field0: final v) => switch (v) {
        SystemEvent_DiskSpaceLow() => true,
        SystemEvent_Error() => true,
        _ => false,
      },
    EventPayload_Sequencer(field0: final v) => switch (v) {
        SequencerEvent_Error() => true,
        _ => false,
      },
    _ => false,
  };
}

// ---------------------------------------------------------------------------
// Variant-specific title/detail mapping.
// ---------------------------------------------------------------------------

String _equipmentTitle(EquipmentEvent v) {
  return switch (v) {
    EquipmentEvent_Connecting() => 'Connecting',
    EquipmentEvent_Connected() => 'Connected',
    EquipmentEvent_Disconnected() => 'Disconnected',
    EquipmentEvent_PropertyChanged() => 'Property changed',
    EquipmentEvent_Error() => 'Device error',
    EquipmentEvent_MountSlewStarted() => 'Mount slew started',
    EquipmentEvent_MountSlewCompleted() => 'Mount slew complete',
    EquipmentEvent_MountTrackingStarted() => 'Tracking started',
    EquipmentEvent_MountTrackingStopped() => 'Tracking stopped',
    EquipmentEvent_MountParkStarted() => 'Park initiated',
    EquipmentEvent_MountParkCompleted() => 'Mount parked',
    EquipmentEvent_MountUnparked() => 'Mount unparked',
    EquipmentEvent_FocuserMoveStarted() => 'Focuser move started',
    EquipmentEvent_FocuserMoveCompleted() => 'Focuser move complete',
    EquipmentEvent_FocuserTemperatureChanged() => 'Focuser temperature',
    EquipmentEvent_FilterChanging() => 'Filter changing',
    EquipmentEvent_FilterChanged() => 'Filter changed',
    EquipmentEvent_RotatorMoveStarted() => 'Rotator move started',
    EquipmentEvent_RotatorMoveCompleted() => 'Rotator move complete',
    EquipmentEvent_CameraCoolingStarted() => 'Cooling started',
    EquipmentEvent_CameraCoolingReached() => 'Cooling reached target',
    EquipmentEvent_CameraWarmingStarted() => 'Warming started',
    EquipmentEvent_CameraWarmingCompleted() => 'Warming complete',
    EquipmentEvent_HeartbeatStarted() => 'Heartbeat started',
    EquipmentEvent_HeartbeatStopped() => 'Heartbeat stopped',
    EquipmentEvent_HeartbeatStatusChanged() => 'Heartbeat status',
    EquipmentEvent_HeartbeatReconnecting() => 'Reconnecting',
    EquipmentEvent_HeartbeatReconnected() => 'Reconnected',
  };
}

String _equipmentDetail(EquipmentEvent v) {
  return switch (v) {
    EquipmentEvent_Connecting(deviceType: final t, deviceId: final id) =>
      '$t · $id',
    EquipmentEvent_Connected(deviceType: final t, deviceId: final id) =>
      '$t · $id',
    EquipmentEvent_Disconnected(deviceType: final t, deviceId: final id) =>
      '$t · $id',
    EquipmentEvent_PropertyChanged(
      deviceType: final t,
      property: final p,
      value: final val
    ) =>
      '$t · $p=$val',
    EquipmentEvent_Error(
      deviceType: final t,
      deviceId: final id,
      message: final m
    ) =>
      '$t/$id: $m',
    EquipmentEvent_MountSlewStarted(ra: final ra, dec: final dec) =>
      'RA ${ra.toStringAsFixed(3)}h Dec ${dec.toStringAsFixed(2)}°',
    EquipmentEvent_MountSlewCompleted(ra: final ra, dec: final dec) =>
      'RA ${ra.toStringAsFixed(3)}h Dec ${dec.toStringAsFixed(2)}°',
    EquipmentEvent_MountTrackingStarted() => '',
    EquipmentEvent_MountTrackingStopped() => '',
    EquipmentEvent_MountParkStarted() => '',
    EquipmentEvent_MountParkCompleted() => '',
    EquipmentEvent_MountUnparked() => '',
    EquipmentEvent_FocuserMoveStarted(targetPosition: final p) =>
      'Target $p',
    EquipmentEvent_FocuserMoveCompleted(position: final p) => 'At $p',
    EquipmentEvent_FocuserTemperatureChanged(temperature: final t) =>
      '${t.toStringAsFixed(1)}°C',
    EquipmentEvent_FilterChanging(
      fromPosition: final from,
      toPosition: final to,
      filterName: final name
    ) =>
      name != null && name.isNotEmpty
          ? '$from → $to ($name)'
          : '$from → $to',
    EquipmentEvent_FilterChanged(position: final p, filterName: final name) =>
      name != null && name.isNotEmpty ? '$name (pos $p)' : 'Position $p',
    EquipmentEvent_RotatorMoveStarted(targetAngle: final a) =>
      'Target ${a.toStringAsFixed(2)}°',
    EquipmentEvent_RotatorMoveCompleted(angle: final a) =>
      '${a.toStringAsFixed(2)}°',
    EquipmentEvent_CameraCoolingStarted(targetTemp: final t) =>
      'Target ${t.toStringAsFixed(1)}°C',
    EquipmentEvent_CameraCoolingReached(temperature: final t) =>
      'At ${t.toStringAsFixed(1)}°C',
    EquipmentEvent_CameraWarmingStarted() => '',
    EquipmentEvent_CameraWarmingCompleted() => '',
    EquipmentEvent_HeartbeatStarted(deviceType: final t, deviceId: final id) =>
      '$t · $id',
    EquipmentEvent_HeartbeatStopped(deviceType: final t, deviceId: final id) =>
      '$t · $id',
    EquipmentEvent_HeartbeatStatusChanged(
      deviceType: final t,
      deviceId: final id,
      status: final s,
      consecutiveFailures: final failures,
    ) =>
      '$t/$id: ${s.name} ($failures fails)',
    EquipmentEvent_HeartbeatReconnecting(
      deviceType: final t,
      deviceId: final id,
      attempt: final n,
      maxAttempts: final max,
    ) =>
      '$t/$id: attempt $n/$max',
    EquipmentEvent_HeartbeatReconnected(
      deviceType: final t,
      deviceId: final id,
      afterAttempts: final n,
    ) =>
      '$t/$id after $n attempts',
  };
}

String _imagingTitle(ImagingEvent v) {
  return switch (v) {
    ImagingEvent_ExposureStarted() => 'Exposure started',
    ImagingEvent_ExposureStartedWithFrame() => 'Exposure started',
    ImagingEvent_ExposureProgress() => 'Exposure progress',
    ImagingEvent_ExposureCompleted() => 'Exposure complete',
    ImagingEvent_ExposureCompletedWithFrame() => 'Exposure complete',
    ImagingEvent_ExposureFailed() => 'Exposure failed',
    ImagingEvent_ExposureCancelled() => 'Exposure cancelled',
    ImagingEvent_DownloadStarted() => 'Download started',
    ImagingEvent_DownloadCompleted() => 'Download complete',
    ImagingEvent_ImageReady() => 'Image ready',
    ImagingEvent_ImageSaved() => 'Image saved',
    ImagingEvent_TemperatureChanged() => 'Camera temperature',
    ImagingEvent_ExposureComplete() => 'Exposure complete',
    ImagingEvent_ExposureFailedOld() => 'Exposure failed',
  };
}

String _imagingDetail(ImagingEvent v) {
  return switch (v) {
    ImagingEvent_ExposureStarted(
      durationSecs: final d,
      frameType: final t
    ) =>
      '${d.toStringAsFixed(1)}s ${t.name}',
    ImagingEvent_ExposureStartedWithFrame(
      durationSecs: final d,
      frameType: final t,
      frameNumber: final n,
      totalFrames: final total,
    ) =>
      total != null
          ? '$n/$total · ${d.toStringAsFixed(1)}s ${t.name}'
          : '#$n · ${d.toStringAsFixed(1)}s ${t.name}',
    ImagingEvent_ExposureProgress(
      progress: final p,
      remainingSecs: final r
    ) =>
      '${(p * 100).toStringAsFixed(0)}% · ${r.toStringAsFixed(0)}s remaining',
    ImagingEvent_ExposureCompleted(
      hfr: final h,
      starsDetected: final stars
    ) =>
      'HFR ${h.toStringAsFixed(2)} · $stars stars',
    ImagingEvent_ExposureCompletedWithFrame(
      frameNumber: final n,
      totalFrames: final total,
      hfr: final h,
      starsDetected: final stars,
    ) =>
      total != null
          ? '$n/$total · HFR ${h.toStringAsFixed(2)} · $stars stars'
          : '#$n · HFR ${h.toStringAsFixed(2)} · $stars stars',
    ImagingEvent_ExposureFailed(error: final err) => err,
    ImagingEvent_ExposureCancelled() => '',
    ImagingEvent_DownloadStarted() => '',
    ImagingEvent_DownloadCompleted() => '',
    ImagingEvent_ImageReady(width: final w, height: final h) => '$w × $h',
    ImagingEvent_ImageSaved(filePath: final p) => p,
    ImagingEvent_TemperatureChanged(
      tempCelsius: final t,
      coolerPower: final pw
    ) =>
      '${t.toStringAsFixed(1)}°C · ${pw.toStringAsFixed(0)}% cooler',
    ImagingEvent_ExposureComplete(success: final s) => s ? 'OK' : 'Failed',
    ImagingEvent_ExposureFailedOld(reason: final r) => r,
  };
}

