String _sequencerTitle(SequencerEvent v) {
  return switch (v) {
    SequencerEvent_Started() => 'Sequence started',
    SequencerEvent_Paused() => 'Sequence paused',
    SequencerEvent_Resumed() => 'Sequence resumed',
    SequencerEvent_Stopped() => 'Sequence stopped',
    SequencerEvent_Completed() => 'Sequence complete',
    SequencerEvent_NodeStarted() => 'Step started',
    SequencerEvent_NodeCompleted() => 'Step finished',
    SequencerEvent_Progress() => 'Progress',
    SequencerEvent_TargetChanged() => 'Target changed',
    SequencerEvent_TargetCompleted() => 'Target complete',
    SequencerEvent_ExposureStarted() => 'Exposure started',
    SequencerEvent_ExposureCompleted() => 'Exposure complete',
    SequencerEvent_Error() => 'Sequencer error',
    SequencerEvent_TriggerFired() => 'Trigger fired',
    SequencerEvent_InstructionProgress() => 'Instruction progress',
  };
}

String _sequencerDetail(SequencerEvent v) {
  return switch (v) {
    SequencerEvent_Started(sequenceName: final n) => n,
    SequencerEvent_Paused() => '',
    SequencerEvent_Resumed() => '',
    SequencerEvent_Stopped() => '',
    SequencerEvent_Completed() => '',
    SequencerEvent_NodeStarted(nodeType: final t) => t,
    SequencerEvent_NodeCompleted(status: final s) => s,
    SequencerEvent_Progress(current: final c, total: final t) => '$c / $t',
    SequencerEvent_TargetChanged(targetName: final n) => n,
    SequencerEvent_TargetCompleted(targetName: final n) => n,
    SequencerEvent_ExposureStarted(
      frame: final f,
      total: final t,
      filter: final flt,
      durationSecs: final d,
    ) =>
      flt != null && flt.isNotEmpty
          ? '$f/$t · $flt · ${d.toStringAsFixed(1)}s'
          : '$f/$t · ${d.toStringAsFixed(1)}s',
    SequencerEvent_ExposureCompleted(
      frame: final f,
      total: final t,
      durationSecs: final d,
    ) =>
      '$f/$t · ${d.toStringAsFixed(1)}s',
    SequencerEvent_Error(message: final m) => m,
    SequencerEvent_TriggerFired(triggerName: final n, action: final a) =>
      '$n → $a',
    SequencerEvent_InstructionProgress(
      instruction: final i,
      progressPercent: final p,
      detail: final d,
    ) =>
      d.isNotEmpty
          ? '$i: $d (${p.toStringAsFixed(0)}%)'
          : '$i (${p.toStringAsFixed(0)}%)',
  };
}

String _safetyTitle(SafetyEvent v) {
  return switch (v) {
    SafetyEvent_WeatherUnsafe() => 'Weather unsafe',
    SafetyEvent_WeatherSafe() => 'Weather safe',
    SafetyEvent_EmergencyStop() => 'Emergency stop',
    SafetyEvent_ParkInitiated() => 'Park initiated',
    SafetyEvent_ParkCompleted() => 'Park complete',
  };
}

String _safetyDetail(SafetyEvent v) {
  return switch (v) {
    SafetyEvent_WeatherUnsafe(reason: final r) => r,
    SafetyEvent_WeatherSafe() => '',
    SafetyEvent_EmergencyStop(reason: final r) => r,
    SafetyEvent_ParkInitiated(reason: final r) => r,
    SafetyEvent_ParkCompleted() => '',
  };
}

String _systemTitle(SystemEvent v) {
  return switch (v) {
    SystemEvent_Initialized() => 'System ready',
    SystemEvent_ShuttingDown() => 'Shutting down',
    SystemEvent_Error() => 'System error',
    SystemEvent_DiskSpaceLow() => 'Disk space low',
    SystemEvent_Notification(title: final t) => t,
    SystemEvent_EventsDropped() => 'Events dropped',
  };
}

String _systemDetail(SystemEvent v) {
  return switch (v) {
    SystemEvent_Initialized() => '',
    SystemEvent_ShuttingDown() => '',
    SystemEvent_Error(message: final m) => m,
    SystemEvent_DiskSpaceLow(availableGb: final gb) =>
      '${gb.toStringAsFixed(1)} GB free',
    SystemEvent_Notification(message: final m, level: final lvl) =>
      lvl.isNotEmpty ? '$m ($lvl)' : m,
    SystemEvent_EventsDropped(droppedCount: final n, totalDropped: final tot) =>
      '$n events dropped (total: $tot)',
  };
}
